/* ===== ES — TX Requisitos especiales (§14) · base 0–35 ===== */
window.I18N.q.es.special = {
  0:{q:"¿Cuál es el ancho máximo legal de un vehículo comercial o su carga en Texas?",options:["96 pulgadas","102 pulgadas","108 pulgadas","120 pulgadas"],explanation:"El ancho máximo legal en Texas es 102 pulgadas (8.5 pies), carga incluida. Algo más ancho requiere permiso de sobredimensión."},
  1:{q:"¿Cuál es la altura máxima de un vehículo y su carga en las carreteras de Texas?",options:["13 pies","13 pies 6 pulg","14 pies","15 pies"],explanation:"Un vehículo y su carga no pueden exceder 14 pies en Texas. Pasar bajo puentes es responsabilidad del conductor, diga lo que diga el letrero."},
  2:{q:"El peso bruto máximo (vehículo más carga) sin permiso es:",options:["72,000 lb","76,000 lb","80,000 lb","90,000 lb"],explanation:"El peso bruto máximo sin permiso es 80,000 lb. Un eje suele limitarse a 20,000 y un tándem a 34,000 lb."},
  3:{q:"El emblema de vehículo lento (SMV) es para vehículos diseñados para ir a:",options:["15 mph o menos","25 mph o menos","35 mph o menos","45 mph o menos"],explanation:"El triángulo naranja fluorescente identifica vehículos que van a 25 mph o menos para que el tráfico rápido reduzca a tiempo."},
  4:{q:"En un camión de 80 pulgadas de ancho, las luces de gálibo delanteras deben ser:",options:["Ámbar","Rojas","Blancas","Verdes"],explanation:"Las luces de gálibo delanteras deben ser ámbar; las traseras, rojas."},
  5:{q:"Las luces de gálibo traseras en un camión ancho deben ser:",options:["Ámbar","Blancas","Rojas","Azules"],explanation:"Las luces de gálibo traseras deben ser rojas."},
  6:{q:"Los dos reflectores exigidos en la parte trasera de un CMV deben ser:",options:["Ámbar","Rojos","Blancos","Verdes"],explanation:"Los reflectores traseros deben ser rojos y visibles para el tráfico que sigue."},
  7:{q:"¿Qué color deben mostrar hacia atrás las luces traseras?",options:["Blanco","Ámbar","Rojo","Azul"],explanation:"Las luces traseras deben mostrar rojo hacia atrás, visible a 1,000 pies."},
  8:{q:"¿Qué color deben mostrar los faros de un vehículo comercial?",options:["Ámbar","Blanco","Amarillo","Azul"],explanation:"Los faros deben ser blancos."},
  9:{q:"Una bandera roja que marca una carga saliente debe medir al menos:",options:["6 pulgadas cuadradas","9 pulgadas cuadradas","12 pulgadas cuadradas","18 pulgadas cuadradas"],explanation:"La bandera roja debe medir al menos 12 pulgadas cuadradas."},
  10:{q:"Una carga debe llevar bandera cuando sobresale por detrás más de:",options:["2 pies","3 pies","4 pies","6 pies"],explanation:"Si sobresale más de 4 pies por detrás, se marca de día con una bandera roja de al menos 12 pulgadas cuadradas."},
  11:{q:"Una carga no puede sobresalir por el frente del vehículo más de:",options:["3 pies","4 pies","6 pies","10 pies"],explanation:"Por el frente la carga no puede sobresalir más de 3 pies."},
  12:{q:"Al remolcar con cadena, la conexión debe mostrar una bandera:",options:["Roja","Blanca","Ámbar","Naranja"],explanation:"La conexión de remolque debe llevar una bandera o tela blanca de al menos 12 pulgadas cuadradas."},
  13:{q:"La conexión de remolque entre dos vehículos no puede ser más larga de:",options:["10 pies","15 pies","20 pies","25 pies"],explanation:"Salvo barra rígida, la conexión no puede exceder 15 pies."},
  14:{q:"Los frenos del remolque en el eje trasero se exigen por encima de un peso bruto de:",options:["2,500 lb","3,000 lb","4,500 lb","10,000 lb"],explanation:"Los remolques de más de 4,500 lb deben tener frenos que actúen sobre las ruedas del eje trasero, con un solo mando al alcance del conductor."},
  15:{q:"Tras hacerse residente de Texas, las placas de otro estado se reconocen por:",options:["10 días","20 días","30 días","60 días"],explanation:"Tienes 30 días para registrar el vehículo en Texas tras hacerte residente."},
  16:{q:"La placa temporal de cartón de un comprador es válida por:",options:["20 días","30 días","45 días","60 días"],explanation:"La placa temporal del comprador es válida 20 días."},
  17:{q:"¿A qué distancia del suelo deben llegar los guardabarros (mud flaps)?",options:["4 pulgadas","6 pulgadas","8 pulgadas","12 pulgadas"],explanation:"Los guardabarros deben llegar a 8 pulgadas del suelo o menos."},
  18:{q:"Al rebasar una motocicleta, debes dejar al menos:",options:["3 pies","6 pies","9 pies","12 pies"],explanation:"Al rebasar una motocicleta deja al menos 6 pies de espacio."},
  19:{q:"Un vehículo único (no un tractocamión) no puede medir más de:",options:["40 pies","45 pies","53 pies","65 pies"],explanation:"Un vehículo único, sin permiso, se limita a 45 pies."},
  20:{q:"El número máximo de vehículos permitido en una combinación es:",options:["2","3","4","5"],explanation:"En Texas se permiten hasta 3 vehículos en una combinación."},
  21:{q:"Las luces traseras deben verse claramente por detrás a:",options:["300 pies","500 pies","750 pies","1,000 pies"],explanation:"Las luces traseras deben verse a 1,000 pies por detrás."},
  22:{q:"Una luz de freno debe verse de día desde al menos:",options:["100 pies","300 pies","500 pies","1,000 pies"],explanation:"Las luces de freno deben verse de día desde al menos 300 pies."},
  23:{q:"De noche, una carga que sobresale más de 4 pies por detrás debe mostrar:",options:["Bandera blanca","Bandera roja","Luz roja","Luz ámbar"],explanation:"De noche, en vez de bandera roja, se usa una luz roja visible a 500 pies."},
  24:{q:"Los reflectores traseros deben montarse a una altura de:",options:["12–48 pulgadas","24–54 pulgadas","24–60 pulgadas","12–60 pulgadas"],explanation:"Los reflectores traseros se montan entre 24 y 60 pulgadas del suelo."},
  25:{q:"Los faros deben montarse a una altura de:",options:["12–48 pulgadas","24–54 pulgadas","24–60 pulgadas","20–50 pulgadas"],explanation:"Los faros se montan entre 24 y 54 pulgadas del suelo."},
  26:{q:"Fuera de una ciudad, un camión no puede seguir a otro camión a menos de:",options:["100 pies","200 pies","300 pies","500 pies"],explanation:"En carretera abierta los camiones deben dejar al menos 300 pies entre sí para que otros puedan rebasar con seguridad."},
  27:{q:"Debes bajar las luces altas ante un vehículo que viene de frente a menos de:",options:["200 pies","300 pies","500 pies","1,000 pies"],explanation:"Baja las luces altas a 500 pies de un vehículo que viene de frente (y a 300 pies si lo sigues)."},
  28:{q:"Una combinación de más de 3,000 lb debe frenar desde 20 mph en menos de:",options:["30 pies","40 pies","50 pies","60 pies"],explanation:"Debe poder detenerse en 50 pies desde 20 mph."},
  29:{q:"¿Qué color de luz NO puede mostrarse hacia el frente de un vehículo?",options:["Blanco","Ámbar","Rojo","Todos están permitidos"],explanation:"No puede mostrarse rojo hacia el frente; el rojo es para atrás."},
  30:{q:"En un cruce de ferrocarril, un camión con placas de hazmat debe:",options:["Detenerse","Verificar que el paso esté libre","Cruzar sin cambiar de marcha","Todo lo anterior"],explanation:"Debe detenerse, verificar que el paso esté libre y cruzar sin cambiar de marcha sobre las vías."},
  31:{q:"¿Cuál de estos NO es un límite de Texas (sin permiso)?",options:["Ancho 102 pulg","Altura 14 pies","Largo 45 pies (único)","Bruto 100,000 lb"],explanation:"El peso bruto máximo sin permiso es 80,000 lb, no 100,000."},
  32:{q:"Las luces traseras se ven a ____; las de freno se ven a ____.",options:["1,000 pies / 300 pies","500 pies / 1,000 pies","300 pies / 1,000 pies","1,000 pies / 500 pies"],explanation:"Traseras a 1,000 pies; freno a 300 pies."},
  33:{q:"Los faros se montan a ____; los reflectores traseros a ____.",options:["24–54 pulg / 24–60 pulg","24–60 pulg / 24–54 pulg","ambos 24–54 pulg","ambos 24–60 pulg"],explanation:"Faros 24–54 pulg; reflectores traseros 24–60 pulg."},
  34:{q:"Al remolcar un vehículo con cadena, ¿qué se exige?",options:["Bandera blanca en la conexión","Conexión no mayor de 15 pies","Cadenas de seguridad de respaldo","Todo lo anterior"],explanation:"Se exige bandera blanca, conexión de máximo 15 pies y cadenas de seguridad de respaldo."},
  35:{q:"¿Cuál de los siguientes es LEGAL en Texas?",options:["Bajar en punto muerto","Mostrar luz roja al frente","Cubrir una carga de grava","Un camión hazmat que se salta un cruce"],explanation:"Cubrir una carga de grava es legal y recomendable; las demás opciones son ilegales."}
};

/* ===== ES — Conocimiento general (§2) · base 0–63 ===== */
