  1:{q:"La profundidad mínima de dibujo para las llantas que no son delanteras es:",options:["1/32 pulg","2/32 pulg","4/32 pulg","6/32 pulg"],explanation:"Las demás llantas necesitan al menos 2/32 de pulgada."},
