  119:{q:"Con los frenos aplicados, la pérdida de aire en un vehículo único debe ser menos de:",options:["10 psi por minuto","3 psi por minuto","30 psi por minuto","0.1 psi por minuto"],explanation:"Menos de 3 psi por minuto."},
  120:{q:"Los ajustadores de holgura muy flojos hacen que:",options:["El motor se caliente","Los frenos trabajen mal","Las luces parpadeen","Las llantas se gasten rápido"],explanation:"Los frenos trabajen mal."},
  121:{q:"El vástago (pushrod) de una cámara de freno no debe moverse más de unas:",options:["Medio pie","1 pulgada","6 pulgadas","2 pies"],explanation:"No más de 1 pulgada."},
  122:{q:"Los tambores o balatas agrietados o muy gastados están:",options:["Bien para usar","Fuera de servicio","Mejor en lluvia","Se reparan solos"],explanation:"Fuera de servicio."},
