  124:{q:"El ABS en frenos de aire sobre todo te ayuda a:",options:["Parar mucho más corto","Mantener la dirección al frenar fuerte","Ahorrar mucho combustible","Cargar mucho más peso"],explanation:"Mantener la dirección en una frenada fuerte."},
  125:{q:"La parte que convierte la presión de aire en la fuerza que aplica los frenos es la:",options:["Compresor de aire","Cámara de freno","Glad hand","Gobernador"],explanation:"La cámara de freno."},
