  127:{q:"El tipo de fundación de freno de aire más común es el:",options:["Freno solo de disco","Freno de tambor de leva en S","Freno de banda de mano","Freno de contrapedal"],explanation:"El freno de tambor de leva en S."},
  128:{q:"Las balatas presionan contra el:",options:["Tanque de aire","Tambor de freno","Volante","Tanque de combustible"],explanation:"El tambor de freno."},
  129:{q:"La perilla amarilla con forma de diamante controla:",options:["Los faros","Los frenos de estacionamiento","El volumen de radio","Los limpiadores"],explanation:"Los frenos de estacionamiento."},
  130:{q:"Debes liberar los frenos de estacionamiento solo tras tener suficiente:",options:["Aceite de motor","Presión de aire","Diésel","Refrigerante"],explanation:"Suficiente presión de aire."},
  131:{q:"Si el sistema de aire tiene una fuga grande al manejar, los frenos al final:",options:["Dejarán de funcionar del todo","Se aplicarán solos","Te acelerarán","Quedarán sueltos"],explanation:"Se aplicarán solos (los de resorte) al perderse el aire."},
  132:{q:"Si pierdes presión de aire al manejar, debes:",options:["Ir más rápido","Parar mientras puedas","Bombear para seguir","Ignorar la alerta"],explanation:"Para mientras todavía puedas."},
