  134:{q:"En un sistema de aire dual, la presión debe subir de 85 a 100 psi en unos:",options:["3 segundos","45 segundos","10 minutos","1 hora"],explanation:"Unos 45 segundos."},
  135:{q:"Una válvula de retención entre tanques evita que el aire:",options:["Se acumule","Regrese si hay una fuga","Llegue a los frenos","Se enfríe demasiado"],explanation:"Regrese (fluya hacia atrás) si hay una fuga."},
  136:{q:"El primer tanque que llena el compresor, donde se junta el agua, es el:",options:["Tanque seco","Tanque húmedo (de suministro)","Tanque de combustible","Tanque de repuesto"],explanation:"El tanque húmedo (de suministro)."},
  137:{q:"Para probar el freno de estacionamiento, avanza suave y el freno debe:",options:["Dejarte rodar","Detener el vehículo","Acelerarte","No hacer nada"],explanation:"Detener el vehículo."},
  138:{q:"Para probar los frenos de servicio, rueda a unas 5 mph y:",options:["Cierra los ojos","Pisa firme el pedal","Acelera fuerte","Enciende la radio"],explanation:"Pisa el pedal con firmeza."},
  139:{q:"Un pedal de freno esponjoso o blando puede indicar:",options:["Frenos perfectos","Un problema en los frenos","Más potencia del motor","Mejor rendimiento"],explanation:"Un problema en los frenos."},
  140:{q:"Si la luz de aviso del ABS sigue encendida, el ABS puede estar:",options:["Funcionando bien","Sin funcionar bien","Nuevo","Totalmente cargado"],explanation:"Sin funcionar bien."},
  141:{q:"Aunque el ABS falle, todavía tienes:",options:["Ningún freno","Tus frenos normales","Solo el claxon","Paradas más rápidas"],explanation:"Tus frenos normales."},
  142:{q:"Los ajustadores de holgura automáticos aún deben:",options:["Ajustarse manejando","Revisarse con regularidad","Quitarse para viajar","Pintarse de rojo"],explanation:"Revisarse con regularidad."},
  143:{q:"Los frenos deben ajustarse por alguien que esté:",options:["Con mucha prisa","Capacitado y calificado","Solo de paso","Recién contratado hoy"],explanation:"Capacitado y calificado."},
  144:{q:"Los tanques de aire deben guardar aire suficiente para:",options:["Un año de viajes","Varias paradas si el compresor falla","Solo una milla corta","Ninguna parada"],explanation:"Varias paradas si el compresor deja de funcionar."},
  145:{q:"Drenas los tanques de aire usando los:",options:["El volante","Las válvulas de drenaje (petcocks)","El acelerador","La manija de la puerta"],explanation:"Las válvulas de drenaje (petcocks)."},
  146:{q:"No debes manejar un vehículo con la alerta de baja presión:",options:["Apagada","Encendida","Quitada","Desconectada"],explanation:"No manejes con la alerta encendida."},
  147:{q:"El interruptor de la luz de freno en un sistema de aire funciona por:",options:["Calor del motor","Presión de aire","La radio","La luz del sol"],explanation:"Por la presión de aire."},
  148:{q:"Antes de liberar los frenos de resorte para manejar, la presión de aire debe estar:",options:["Lo más baja posible","Lo bastante alta","Exactamente en cero","En cualquier cantidad"],explanation:"Lo bastante alta."},
  149:{q:"Los tambores de freno muy calientes pueden hacer que los frenos:",options:["Trabajen mejor","Se desvanezcan y pierdan fuerza","Duren más","Agarren más"],explanation:"Se desvanezcan (fade) y pierdan fuerza."},
  150:{q:"La válvula que conserva el aire del tractor si el remolque se suelta es la:",options:["Válvula de relevo","Válvula de protección del tractor","Válvula de liberación rápida","Válvula de pie"],explanation:"La válvula de protección del tractor."},
  151:{q:"Metes la perilla roja octagonal del aire del remolque para:",options:["Cortar el aire del remolque","Dar aire al remolque","Sonar el claxon","Trabar las puertas"],explanation:"Dar aire al remolque."},
  152:{q:"La válvula de protección del tractor se cierra sola cuando el aire baja a unos:",options:["80 a 90 psi","20 a 45 psi","100 a 120 psi","150 psi exactos"],explanation:"Entre 20 y 45 psi."},
  153:{q:"Una válvula de relevo ayuda a que los frenos traseros:",options:["Se suelten lento","Apliquen más rápido","Queden apagados","Se bloqueen"],explanation:"Apliquen más rápido."},
  154:{q:"Una válvula de liberación rápida ayuda a que los frenos:",options:["Apliquen lento","Se suelten más rápido","Queden trabados","Se calienten"],explanation:"Se suelten más rápido."},
  155:{q:"Los frenos de resorte se pueden liberar para remolcar:",options:["Agregando más aire","Enjaulándolos (caging) manualmente","Cortando las líneas","Tocando dos veces"],explanation:"Enjaulándolos (caging) manualmente."},
  156:{q:"Los frenos de las ruedas delanteras de un camión son:",options:["Inútiles y riesgosos","Importantes y necesarios","Solo de adorno","Mejor quitarlos"],explanation:"Importantes y necesarios."},
  157:{q:"La idea de que los frenos delanteros causan patinazos es:",options:["Totalmente cierta","Falsa","Siempre correcta","Un hecho probado"],explanation:"Falsa."},
  158:{q:"El retardo del freno a unas 55 mph agrega aproximadamente:",options:["2 pies","32 pies","300 pies","1 milla"],explanation:"Unos 32 pies."},
  159:{q:"La distancia total de frenado con aire incluye percepción, reacción, retardo del freno y:",options:["El calentamiento del motor","La distancia efectiva de frenado","El consumo de combustible","El giro de las llantas"],explanation:"La distancia efectiva de frenado."},
  160:{q:"En una bajada larga, la forma correcta de frenar es:",options:["Pisar fuerte los frenos","Usar marcha baja y frenado ligero","Bajar en punto muerto","Bombear muy rápido"],explanation:"Marcha baja y frenado ligero."},
  161:{q:"El frenado 'snub' en una pendiente significa frenar para reducir y luego:",options:["Mantener los frenos pisados","Soltar y volver a frenar","Acelerar fuerte","Apagar el motor"],explanation:"Soltar y volver a frenar."},
  162:{q:"Debes elegir tu marcha para una bajada:",options:["A media bajada","Antes de empezar a bajar","Justo al fondo","Solo si hace falta"],explanation:"Antes de empezar a bajar."},
  163:{q:"Las balatas demasiado delgadas están:",options:["Bien para usar","Fuera de servicio","Mejor en lluvia","Se renuevan solas"],explanation:"Fuera de servicio."},
  164:{q:"Al jalar un ajustador de holgura manual, debe moverse:",options:["Un pie entero","Menos de 1 pulgada","Seis pulgadas","Dos pies"],explanation:"Menos de 1 pulgada."},
  165:{q:"Por el retardo del freno de aire, debes empezar a frenar:",options:["Mucho más tarde","Un poco antes","Nunca","Solo en bajada"],explanation:"Un poco antes."},
  166:{q:"Pisar el freno todo el tiempo en una bajada larga hace que se:",options:["Enfríen rápido","Sobrecalienten","Trabajen mejor","Duren más"],explanation:"Se sobrecalienten."},
  167:{q:"Tras pasar por agua honda, debes:",options:["Acelerar de inmediato","Secar los frenos","Apagar el motor","Agregar más aire"],explanation:"Secar los frenos frenando suave."},
  168:{q:"Al estacionar en una pendiente, usa el freno de estacionamiento y también:",options:["Abre las puertas","Pon cuñas en las ruedas","Toca el claxon","Destella las luces"],explanation:"Pon cuñas en las ruedas."},
  169:{q:"En la inspección a pie, escuchas en los frenos si hay:",options:["Música fuerte","Fugas de aire","La radio","Cantos de pájaros"],explanation:"Fugas de aire."},
