  46:{q:"Para estacionar una combinación con seguridad, debes:",options:["Dejarla solo en marcha","Poner los frenos y poner cuñas","Dejar el motor en ralentí","Bajar el techo del remolque"],explanation:"Pon los frenos y cuñas en las ruedas."},
  47:{q:"La válvula de mano del remolque NO debe usarse:",options:["Para una prueba rápida de freno","Para sostener un remolque estacionado","Solo en una rampa empinada","Solo en plano"],explanation:"Para sostener un remolque estacionado."},
  48:{q:"Usar solo la válvula de mano del remolque en un patinazo puede causar:",options:["Una parada suave","Un patinazo del remolque o jackknife","Un viaje más rápido","Un motor más frío"],explanation:"Un patinazo del remolque o jackknife."},
  49:{q:"Comparados con cargados, los remolques vacíos:",options:["Agarran mejor el camino","Rebotan y patinan más fácil","Siempre paran más rápido","Nunca se vuelcan"],explanation:"Rebotan y patinan más fácil."},
  50:{q:"El cable eléctrico (pigtail) entre tractor y remolque alimenta:",options:["El motor del tractor","Las luces y el ABS del remolque","Las llantas del tractor","La quinta rueda"],explanation:"Las luces y el ABS del remolque."},
  51:{q:"Debes inspeccionar el montaje de la quinta rueda por:",options:["Un aspecto limpio y brillante","Grietas y pernos flojos o faltantes","Solo el color correcto","Una radio que funcione"],explanation:"Grietas y pernos flojos o faltantes."},
  52:{q:"Una quinta rueda deslizable te permite:",options:["Cambiar su color","Mover peso entre los ejes","Agregar asientos","Poner música"],explanation:"Mover peso entre los ejes."},
