  57:{q:"Si el kingpin no está trabado en la quinta rueda, el remolque puede:",options:["Frenar mejor","Soltarse del tractor","Ir más rápido","Ahorrar combustible"],explanation:"Soltarse del tractor."},
  58:{q:"La distancia de frenado de una combinación cargada es:",options:["Más corta que la de un auto","Más larga que la de un vehículo ligero","Cero pies","Igual a la de un auto chico"],explanation:"Más larga que la de un vehículo ligero."},
