  113:{q:"Antes de desenganchar, debes estacionar en:",options:["Una loma empinada","Suelo firme y nivelado","Lodo profundo","Un camino concurrido"],explanation:"Suelo firme y nivelado."},
  114:{q:"Al desenganchar, baja el tren de aterrizaje hasta que:",options:["Quede en el aire","Apenas toque el suelo","Se doble","Se salga"],explanation:"Hasta que apenas toque el suelo."},
  115:{q:"Tras bajar el tren de aterrizaje, tú:",options:["Sales rápido","Desconectas las líneas","Tocas dos veces","Inflas las llantas"],explanation:"Desconectas las líneas."},
  116:{q:"Debes asegurar las líneas de aire desconectadas para que:",options:["Solo se vean ordenadas","No arrastren ni se ensucien","Queden calientes","Hagan ruido"],explanation:"Para que no arrastren ni se ensucien."},
