  76:{q:"Un tanque de 'interior liso' (smooth bore) tiene:",options:["Muchos baffles adentro","Sin baffles ni mamparos adentro","Paredes muy gruesas","Doble fondo"],explanation:"Sin baffles ni mamparos adentro."},
