  85:{q:"Un centro de gravedad alto hace que una cisterna sea más propensa a:",options:["Parar muy rápido","Volcarse en una curva","Buen rendimiento","Dirección ligera"],explanation:"Volcarse en una curva."},
  86:{q:"La mayoría de las volcaduras de cisterna ocurren porque el conductor:",options:["Manejó muy lento","Tomó una curva o rampa muy rápido","Guardó mucha distancia","Revisó los espejos"],explanation:"Tomó una curva o rampa demasiado rápido."},
  87:{q:"Si quitas el pie del freno muy pronto en una cisterna, el oleaje puede:",options:["Parar el camión más rápido","Empujarte hacia una intersección","Enfriar los frenos","Bloquear las ruedas a salvo"],explanation:"Empujarte hacia adelante, hacia una intersección."},
  88:{q:"Se necesita cuidado especial en una cisterna en:",options:["Caminos rectos y secos","Caminos mojados, curvas y rampas","Estacionamientos vacíos","Autopistas planas y largas"],explanation:"Caminos mojados, curvas y rampas."},
  89:{q:"Debes manejar una cisterna más suave que un caja seca por:",options:["Mejores frenos","El oleaje del líquido","Menos peso","Espejos más grandes"],explanation:"El oleaje del líquido."},
  90:{q:"Al cargar una cisterna, debes mantener la carga:",options:["Lo más alto posible","Dentro del peso legal y bien balanceada","Siempre atrás","Siempre adelante"],explanation:"Dentro del peso legal y bien balanceada."},
  91:{q:"Si tu cisterna tiene una fuga de líquido, debes:",options:["Seguir a la entrega","Parar, asegurar la zona y pedir ayuda","Acelerar para terminar","Abrir todas las válvulas"],explanation:"Para, asegura la zona y pide ayuda."},
  92:{q:"El corte de emergencia de una cisterna (si lo tiene) sirve para:",options:["Arrancar la bomba","Detener el flujo del producto en una emergencia","Enfriar la carga","Inflar las llantas"],explanation:"Detener el flujo del producto en una emergencia."},
  93:{q:"Al cargar combustible o líquidos inflamables, debes:",options:["Fumar cerca con calma","Conectar a tierra y mantener lejos las fuentes de ignición","Mantener el motor acelerado","Usar el celular libremente"],explanation:"Conecta a tierra (bond/ground) y mantén lejos las fuentes de ignición."},
  94:{q:"Como una cisterna va alta y vuelca fácil, tu velocidad en una curva debe ser:",options:["Exactamente la señalada","Varias mph por debajo de la velocidad de la curva","Un poco sobre la señalada","La que quiera el camión"],explanation:"Varias mph por debajo de la velocidad señalada de la curva."},
  95:{q:"El oleaje puede afectar una cisterna incluso cuando:",options:["Está estacionada y apagada","Cambias de carril o paras","Tienes la radio puesta","Bajas las ventanas"],explanation:"Cuando cambias de carril o paras."},
  96:{q:"Cuando un tanque tiene compartimientos llenos y vacíos, cargas para mantener:",options:["Todo el peso atrás","Los pesos por eje legales y balanceados","Todo el peso adelante","El tanque bonito"],explanation:"Los pesos por eje legales y balanceados."},
  97:{q:"La forma más segura de manejar el oleaje al frenar para un semáforo es:",options:["Frenar fuerte al último segundo","Empezar a frenar temprano y suave","Bombear los frenos rápido","Bajar en punto muerto"],explanation:"Empezar a frenar temprano y suave."},
  98:{q:"¿Cuál afirmación sobre cisternas es VERDADERA?",options:["Los tanques llenos siempre tienen más oleaje","Un centro de gravedad alto eleva el riesgo de volcadura","Los tanques vacíos nunca rebotan","El oleaje te ayuda a parar más rápido"],explanation:"Un centro de gravedad alto eleva el riesgo de volcadura."},
  99:{q:"¿Cuál NO es una práctica inteligente al manejar una cisterna cargada?",options:["Reducir antes de las curvas","Frenar fuerte y tarde","Dejar espacio extra adelante","Dirigir con suavidad"],explanation:"Frenar fuerte y tarde."},
  100:{q:"El centro de gravedad alto de una cisterna la hace propensa a:",options:["Mejor rendimiento","Volcadura","Paradas más rápidas","Menos desgaste de llantas"],explanation:"Volcadura."},
  101:{q:"El líquido que se mueve de un lado a otro en un tanque se llama:",options:["Deriva","Oleaje (surge)","Giro","Arrastre"],explanation:"Oleaje (surge)."},
  102:{q:"El oleaje hacia adelante puede empujar el camión justo después de que:",options:["Aceleras","Frenas hasta parar","Pones la radio","Abres una ventana"],explanation:"Después de frenar hasta detenerte."},
  103:{q:"Los baffles en un tanque ayudan a controlar:",options:["Oleaje de lado a lado","Oleaje de adelante hacia atrás","Calor del motor","Consumo"],explanation:"El oleaje de adelante hacia atrás."},
