  56:{q:"Un autobús con pasajeros nunca debe llevar ¿cuál de estos?",options:["Agua embotellada sellada","Explosivos Clase 1","Sillas de ruedas plegadas","Bolsas de mano pequeñas"],explanation:"Explosivos Clase 1."},
