  166:{q:"Un autobús cargado necesita más:",options:["Algo de pintura","Distancia de frenado","Una radio","Espejos laterales"],explanation:"Distancia de frenado."},
  167:{q:"En una loma, los estudiantes igual cruzan al menos:",options:["1 pie adelante","10 pies adelante","Detrás del autobús","Bajo el autobús"],explanation:"Al menos 10 pies adelante."},
  168:{q:"Después de la última parada, las luces de advertencia deben estar:",options:["Dejadas parpadeando","Apagadas","Pintadas encima","Quitadas"],explanation:"Apagadas."},
  169:{q:"Los espejos crossover muestran el área:",options:["Muy atrás","Enfrente del autobús","Dentro del motor","En el techo"],explanation:"Enfrente del autobús."},
  170:{q:"En una autopista dividida, el tráfico detrás del autobús debe:",options:["Pasarlo","Parar","Acelerar","Rodearlo"],explanation:"Parar."},
  171:{q:"Debes señalar a los estudiantes cuando sea seguro:",options:["Comer","Cruzar","Dormir","Cantar"],explanation:"Cruzar."},
  172:{q:"Una parada de autobús escolar debe hacerse donde los estudiantes estén:",options:["Escondidos","Visibles y seguros","En el tráfico","En las vías"],explanation:"Visibles y seguros."},
  173:{q:"Debes saber dónde está cada estudiante antes de:",options:["Comer","Mover el autobús","Cantar","Tomar una siesta"],explanation:"Mover el autobús."},
  174:{q:"El trabajo principal del conductor en una parada es:",options:["Poner música","Mantener seguros a los estudiantes","Leer un libro","Lavar el autobús"],explanation:"Mantener seguros a los estudiantes."},
  175:{q:"El mayor riesgo para los estudiantes cerca de un autobús es ser golpeados por:",options:["Una bicicleta","El autobús o el tráfico","Una gota de lluvia","Una mochila"],explanation:"El autobús o el tráfico."},
  176:{q:"A muchos estudiantes lesionados en la zona de peligro los golpea:",options:["Un auto estacionado","Su propio autobús","Una bicicleta","Un scooter"],explanation:"Su propio autobús."},
  177:{q:"Un niño que dejó caer algo cerca del autobús debe:",options:["Gatear debajo","Avisar primero al conductor","Agarrarlo rápido","Patearlo lejos"],explanation:"Avisar primero al conductor."},
  178:{q:"Al descargar, vigila que los estudiantes:",options:["Se queden debajo","Se alejen del autobús","Se escondan cerca","Se sienten en las llantas"],explanation:"Se alejen del autobús."},
  179:{q:"Un conductor de autobús debe estar especialmente atento en:",options:["Campos vacíos","Paradas cerca del tráfico","Áreas de descanso","Carreteras anchas"],explanation:"Paradas cerca del tráfico."},
  180:{q:"El brazo de alto y las luces advierten a:",options:["Los estudiantes","Los otros conductores","El motor","La radio"],explanation:"Los otros conductores."},
