  184:{q:"Un autobús escolar está entre los vehículos más seguros cuando:",options:["Es nuevo","Se siguen las reglas","Es rojo","Es rápido"],explanation:"Se siguen las reglas."},
  185:{q:"Los niños más pequeños pueden calcular mal el tráfico, así que debes:",options:["Apurarlos","Guiarlos con cuidado","Ignorarlos","Tocarles el claxon"],explanation:"Guiarlos con cuidado."},
  186:{q:"El conductor controla cuándo cruzan los estudiantes dando:",options:["Algo de dinero","Una señal","Bocadillos gratis","Un bocinazo"],explanation:"Una señal."},
  187:{q:"Tras cargar, antes de arrancar, revisa los:",options:["La guantera","Espejos y zonas de peligro","El dial de radio","El color del asiento"],explanation:"Espejos y zonas de peligro."},
  188:{q:"En el lado derecho, la zona de peligro se extiende unos:",options:["1 pulgada","10 pies o más","Como una milla","Solo una yarda"],explanation:"Unos 10 pies o más."},
  189:{q:"Detrás del autobús, la zona de peligro se extiende:",options:["Nada","Bastante atrás","Solo una pulgada","Hasta el techo"],explanation:"Bastante atrás."},
  190:{q:"Un estudiante debe subir solo cuando el autobús esté:",options:["Aún en movimiento","Parado, puerta abierta","Acelerando","En una vuelta cerrada"],explanation:"Parado, con la puerta abierta."},
  191:{q:"Al acercarte a una parada, reduce la velocidad:",options:["De golpe","Gradual y suave","Después de parar","Viendo de lado"],explanation:"Gradual y suave."},
  192:{q:"Un autobús escolar cargado en hielo debe:",options:["Acelerar","Reducir y agregar distancia","Frenar fuerte","Pegarse mucho"],explanation:"Reducir y agregar distancia."},
  193:{q:"No dejes que los estudiantes saquen brazos o cabeza:",options:["Hacia los asientos","Por las ventanas","Cerca de los pasamanos","Bajo los asientos"],explanation:"Por las ventanas."},
  194:{q:"Vigila las zonas de peligro especialmente durante:",options:["La marcha en carretera","La carga y la descarga","Las paradas de combustible","Los estacionamientos"],explanation:"La carga y la descarga."},
  195:{q:"Ante un autobús escolar parado con luces rojas, los conductores deben:",options:["Pasarlo","Parar","Tocar fuerte","Acelerar"],explanation:"Parar."},
  196:{q:"Si tu vista de un niño está bloqueada, debes:",options:["Moverte de todos modos","Esperar hasta poder ver","Tocar y seguir","Acelerar rápido"],explanation:"Esperar hasta poder ver."},
  197:{q:"Un conductor de autobús escolar seguro siempre:",options:["Sale rápido","Da cuenta de cada estudiante","Se salta los conteos","Maneja a ciegas"],explanation:"Da cuenta de cada estudiante."},
  198:{q:"El interior del autobús debe permitirte:",options:["Esconder estudiantes","Ver y oír a los estudiantes","Bloquear la vista","Quedar oscuro"],explanation:"Ver y oír a los estudiantes."},
