  71:{q:"¿De qué color deben ser los reflectores de la parte trasera de un vehículo comercial?",options:["Ámbar (amarillo)","Rojo","Verde","Azul"],explanation:"Rojos."},
  72:{q:"Hacia el frente, las lámparas de gálibo y de posición laterales deben ser de qué color?",options:["Rojo","Ámbar (amarillo)","Verde","Blanco"],explanation:"Ámbar hacia el frente."},
  73:{q:"Sin permiso especial, lo más pesado que puede ser legalmente un vehículo cargado es:",options:["60,000 lb","80,000 lb","100,000 lb","120,000 lb"],explanation:"80,000 lb sin permiso."},
  74:{q:"Una carga más ancha de ¿cuántas pulgadas requiere permiso en Texas?",options:["96 pulg (8 pies)","102 pulg (8.5 pies)","108 pulg (9 pies)","120 pulg (10 pies)"],explanation:"Más de 102 pulgadas requiere permiso."},
  75:{q:"Un vehículo y carga más altos de ¿qué altura necesitan permiso?",options:["12 pies","14 pies","16 pies","18 pies"],explanation:"Más de 14 pies requiere permiso."},
