  77:{q:"La ley Move Over / Slow Down de Texas cubre ¿qué vehículos detenidos?",options:["Solo patrullas de policía","Policía, bomberos, EMS, grúas y TxDOT","Solo autobuses escolares","Solo autos particulares"],explanation:"Policía, bomberos, EMS, grúas y TxDOT."},
  78:{q:"Tras detenerte en el acotamiento, ¿en cuánto tiempo debes colocar dispositivos de advertencia?",options:["En 1 minuto","En 10 minutos","En 30 minutos","En 1 hora"],explanation:"Dentro de 10 minutos."},
