  114:{q:"Un vehículo de 60 pies a 55 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["6 segundos","7 segundos","8 segundos","5 segundos"],explanation:"6 por largo + 1 sobre 40 mph = 7 segundos."},
  115:{q:"Un vehículo de 30 pies a 30 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["2 segundos","3 segundos","4 segundos","5 segundos"],explanation:"3 segundos (1 por cada 10 pies, sin extra)."},
  116:{q:"Un vehículo de 70 pies a 50 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["7 segundos","8 segundos","9 segundos","6 segundos"],explanation:"7 por largo + 1 sobre 40 mph = 8 segundos."},
  117:{q:"Un vehículo de 20 pies a 25 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["1 segundo","2 segundos","3 segundos","4 segundos"],explanation:"2 segundos (1 por cada 10 pies)."},
  118:{q:"Un vehículo de 80 pies a 60 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["8 segundos","9 segundos","10 segundos","7 segundos"],explanation:"8 por largo + 1 sobre 40 mph = 9 segundos."},
  119:{q:"Un vehículo de 50 pies a 45 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["5 segundos","6 segundos","7 segundos","4 segundos"],explanation:"5 por largo + 1 sobre 40 mph = 6 segundos."},
  120:{q:"Un vehículo de 60 pies a 35 mph necesita ¿cuántos segundos de distancia de seguimiento?",options:["5 segundos","6 segundos","7 segundos","8 segundos"],explanation:"6 segundos (1 por cada 10 pies, sin extra bajo 40 mph)."},
  121:{q:"¿Cuál de estas puede causar que un vehículo patine?",options:["Ir muy rápido para las condiciones","Frenar muy fuerte en pánico","Acelerar demasiado fuerte","Todas las anteriores"],explanation:"Todas las anteriores pueden causar un patinazo."},
