  148:{q:"A unos 55 mph, la distancia de reacción promedio por sí sola es de unos:",options:["Unos 6 pies","Unos 60 pies","Unos 600 pies","Unas 6 pulgadas"],explanation:"Unos 60 pies solo de reacción."},
